      const match = addr.match(/<(.+)>/) || [null, addr];
      const email = match[1].toLowerCase().replace(/[<>]/g, '').trim();
      recipientCounts[email] = (recipientCounts[email] || 0) + 1;
    });
  }
});

const top3 = Object.entries(recipientCounts)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 3)
  .map(([email, count]) => `${email} (${count})`)
  .join(", ");

// 4. Reply Rate & Response Time
let repliesReceived = 0;
const responseTimes = [];

// For reply rate, we need to see if any thread with a sent message has an incoming message AFTER that sent message
