import { execSync } from "child_process";

// 1. Get sent messages from last 30 days
const query = "is:sent after:2026-02-15"; // Approximately 30 days before Mar 17, 2026
const params = JSON.stringify({ userId: "me", q: query, maxResults: 500 }).replace(/"/g, '\\"');
const sentListCmd = `gws gmail users messages list --params "${params}" --format json`;
const sentList = JSON.parse(execSync(sentListCmd).toString());

if (!sentList.messages) {
  console.log("TotalSent: 0");
  console.log("TopRecipients: N/A");
  console.log("ReplyRate: 0%");
  console.log("AvgResponseTimeHours: 0.0");
  process.exit(0);
}

const sentMessages: any[] = [];
const threadMap = new Map<string, any[]>();

for (const msg of (sentList.messages || [])) {
  const msgParams = JSON.stringify({ userId: "me", id: msg.id, format: "metadata" }).replace(/"/g, '\\"');
  const msgDetailCmd = `gws gmail users messages get --params "${msgParams}" --format json`;
  const detail = JSON.parse(execSync(msgDetailCmd).toString());
  sentMessages.push(detail);

  if (!threadMap.has(detail.threadId)) {
    threadMap.set(detail.threadId, []);
  }
  threadMap.get(detail.threadId).push(detail);
}

// 2. Total Sent
const totalSent = sentMessages.length;

// 3. Top Recipients
const recipientCounts: Record<string, number> = {};
sentMessages.forEach((msg: any) => {
  const headers = msg.payload.headers;
  const toHeader = headers.find((h: any) => h.name === 'To' || h.name === 'to');
  if (toHeader) {
    const addresses = toHeader.value.split(',').map((s: string) => s.trim());
    addresses.forEach((addr: string) => {
      // Extract email from "Name <email@domain.com>" or just "email@domain.com"
      const match = addr.match(/<(.+)>/) || [null, addr];
      const email = match[1]!.toLowerCase().replace(/[<>]/g, '').trim();
      recipientCounts[email] = (recipientCounts[email] || 0) + 1;
    });
  }
});

const top3 = Object.entries(recipientCounts)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 3)
  .map(([email, count]) => `${email} (${count})`)
  .join(", ");

// 4. Reply Rate & Response Time
let repliesReceived = 0;
const responseTimes: number[] = [];

// For reply rate, we need to see if any thread with a sent message has an incoming message AFTER that sent message
const checkedThreads = new Set<string>();

for (const msg of sentMessages as any[]) {
  const threadId = msg.threadId;
  if (checkedThreads.has(threadId)) continue;
  checkedThreads.add(threadId);

  const threadParams = JSON.stringify({ userId: "me", id: threadId }).replace(/"/g, '\\"');
  const threadCmd = `gws gmail users threads get --params "${threadParams}" --format json`;
  const thread = JSON.parse(execSync(threadCmd).toString());

  const messages = thread.messages.sort((a, b) => parseInt(a.internalDate) - parseInt(b.internalDate));

  let sentFound = false;
  let replyBack = false;

  for (let i = 0; i < messages.length; i++) {
    const current = messages[i];
    const isSent = current.labelIds && current.labelIds.includes('SENT');
    const isInbox = current.labelIds && current.labelIds.includes('INBOX');

    if (isSent) {
      sentFound = true;
      // Check if there was a preceding message in INBOX for response time
      if (i > 0) {
        const prev = messages[i-1];
        const prevIsInbox = prev.labelIds && prev.labelIds.includes('INBOX');
        if (prevIsInbox) {
          const diffMs = parseInt(current.internalDate) - parseInt(prev.internalDate);
          if (diffMs > 0) {
             responseTimes.push(diffMs / (1000 * 60 * 60));
          }
        }
      }
    } else if (sentFound && isInbox) {
      replyBack = true;
    }
  }

  if (replyBack) repliesReceived++;
}

const replyRate = ((repliesReceived / checkedThreads.size) * 100).toFixed(1);
const avgResponseTime = responseTimes.length > 0 
  ? (responseTimes.reduce((a, b) => a + b, 0) / responseTimes.length).toFixed(1)
  : "0.0";

console.log(`TotalSent: ${totalSent}`);
console.log(`TopRecipients: ${top3}`);
console.log(`ReplyRate: ${replyRate}%`);
console.log(`AvgResponseTimeHours: ${avgResponseTime}`);

